async function createDeuce(userId: string, data: ReturnType<typeof validateDeuce>) {
  const today = new Date().toISOString().split("T")[0];
  const count = await db.query("SELECT COUNT(*) FROM deuces WHERE user_id = $1 AND DATE(created_at) = $2", [userId, today]);
